// Assuming you have already established a database connection using PDO
function generateReport($pdo) {
    // Fetching filters from $_POST
    $status = $_POST['status'];
    $category = $_POST['category'];
    $startDate = $_POST['start_date'];
    $endDate = $_POST['end_date'];
    
    // Building the base SQL query
    $sql = "SELECT * FROM your_table"; 
  
    // Adding conditions based on filters
    $conditions = [];
    if (!empty($status)) {
        $conditions[] = "status = :status";
    }
    if (!empty($category)) {
        $conditions[] = "category = :category";
    }
    if (!empty($startDate) && !empty($endDate)) {
        $conditions[] = "date BETWEEN :start_date AND :end_date";
    }
  
    // If any conditions were added, we add them to the SQL query
    if (count($conditions) > 0) {
        $sql .= " WHERE " . implode(" AND ", $conditions);
    }
    
    $stmt = $pdo->prepare($sql);
  
    // Bind values based on conditions
    if (!empty($status)) {
        $stmt->bindValue(':status', $status);
    }
    if (!empty($category)) {
        $stmt->bindValue(':category', $category);
    }
    if (!empty($startDate) && !empty($endDate)) {
        $stmt->bindValue(':start_date', $startDate);
        $stmt->bindValue(':end_date', $endDate);
    }
  
    $stmt->execute();
    
    // Fetching and returning the results
    return $stmt->fetchAll(PDO::FETCH_ASSOC);
}
